    total = 0
    for x in nums:
        y = target - x
        if y < x:
            break  # would double-count; but we need exact count, so use different logic
    # Actually let's just do the standard O(n) approach with a running counter
    freq2 = Counter(nums)
    total = 0
    seen = {}
    for i, x in enumerate(nums):
        y = target - x
        if y in seen:
            total += seen[y]
        seen[x] = seen.get(x, 0) + 1
    return total


